-- Generated import for old CRM inquiries and discussion streams.
-- Source: C:\Users\NEW PC\Downloads\old_database.sql
-- Target: new CRM inquiries + streams only.
SET FOREIGN_KEY_CHECKS=0;
START TRANSACTION;



-- Remap imported history to the live Super Admin if exported user IDs do not exist in the target database.
UPDATE `inquiries` SET `assigned_user_id` = (SELECT `id` FROM `users` WHERE `role` = 'super_admin' ORDER BY `id` LIMIT 1) WHERE `assigned_user_id` IS NOT NULL AND `assigned_user_id` NOT IN (SELECT `id` FROM `users`);
UPDATE `streams` SET `user_id` = (SELECT `id` FROM `users` WHERE `role` = 'super_admin' ORDER BY `id` LIMIT 1) WHERE `user_id` NOT IN (SELECT `id` FROM `users`);

ALTER TABLE `inquiries` AUTO_INCREMENT = 462;
SET FOREIGN_KEY_CHECKS=1;
COMMIT;

